// CODIGO CIVIL COLOMBIANO - PARTE 1 (Artículos 1-500)
// Ley 57 de 1887

export const codigoCivilParte1 = {
  codigo: "CC",
  nombre: "Código Civil Colombiano",
  descripcion: "Ley 57 de 1887 - Regula las relaciones civiles entre personas",
  categoria: "Derecho Civil",
  fechaExpedicion: "1887-04-15",
  vigente: true,
  articulos: [
    // TITULO PRELIMINAR
    { numero: "1", titulo: "De la ley", contenido: "La ley es una declaración de la voluntad soberana manifestada en la forma prevenida en la Constitución Nacional. El carácter general de la ley es mandar, prohibir, permitir o castigar." },
    { numero: "2", titulo: "Costumbre", contenido: "La costumbre en ningún caso tiene fuerza contra la ley. No podrá alegarse el desuso para su inobservancia, ni práctica, por inveterada y general que sea." },
    { numero: "3", titulo: "Validez de la ley", contenido: "La ley es obligatoria y surte sus efectos desde el día en que ella misma designe; y en todo caso, después de su promulgación." },
    { numero: "4", titulo: "Ignorancia de la ley", contenido: "La ignorancia de la ley no sirve de excusa." },
    { numero: "5", titulo: "Definición legal", contenido: "La definición legal de palabras técnicas de toda ciencia o arte se aplicarán a la interpretación de las leyes, a menos que aparezca claramente que se han tomado en sentido diverso." },
    { numero: "6", titulo: "Interpretación de la ley", contenido: "Las palabras de la ley se entenderán en su sentido natural y obvio, según el uso general de las mismas palabras; pero cuando el legislador las haya definido expresamente para ciertas materias, se les dará en éstas su significado legal." },
    { numero: "7", titulo: "Expresiones técnicas", contenido: "Las expresiones técnicas de toda ciencia o arte se tomarán en el sentido que les den los que profesan la misma ciencia o arte, a menos que aparezca claramente que se han tomado en sentido diverso." },
    { numero: "8", titulo: "Contexto de la ley", contenido: "El contexto de la ley servirá para ilustrar el sentido de cada una de sus partes, de manera que haya entre todas ellas la debida correspondencia y armonía." },
    { numero: "9", titulo: "Espíritu de la legislación", contenido: "Lo favorable u odioso de una disposición no se tomará en cuenta para ampliar o restringir su interpretación. La extensión que deba darse a toda ley se determinará por su genuino sentido, y según las reglas de interpretación precedentes." },
    { numero: "10", titulo: "Analogía", contenido: "Los pasajes oscuros de una ley pueden ser ilustrados por medio de otras leyes, particularmente si versan sobre el mismo asunto." },
    { numero: "11", titulo: "Equidad natural", contenido: "A falta de ley, se aplicarán las que regulen casos o materias semejantes, y en su defecto, la doctrina constitucional y las reglas generales de derecho." },
    { numero: "12", titulo: "Derechos nacionales", contenido: "Las disposiciones de este Código regirán a todos los habitantes del territorio nacional, comprendiéndose también a los extranjeros, en cuanto a los bienes situados en él, y a las obligaciones que se contraigan respecto de los mismos." },
    { numero: "13", titulo: "Renuncia de derechos", contenido: "Podrán renunciarse los derechos conferidos por las leyes, con tal que solo miren al interés individual del renunciante, y que no esté prohibida la renuncia." },
    { numero: "14", titulo: "Fraude a la ley", contenido: "La ley es obligatoria tanto a los nacionales como a los extranjeros residentes en Colombia." },
    { numero: "15", titulo: "Estado civil", contenido: "El estado civil de las personas se prueba por medio de las partidas del registro civil." },
    { numero: "16", titulo: "Derechos civiles", contenido: "Los derechos civiles son igualmente gozados por todos los colombianos, de conformidad con las leyes." },
    { numero: "17", titulo: "Personas extranjeras", contenido: "Los extranjeros gozan en Colombia de los mismos derechos civiles que los colombianos, salvo las restricciones que establezcan la Constitución o la ley." },
    { numero: "18", titulo: "Mayoría de edad", contenido: "Es mayor de edad la persona que ha cumplido dieciocho años." },
    { numero: "19", titulo: "Domicilio", contenido: "El domicilio consiste en la residencia acompañada, real o presuntivamente, del ánimo de permanecer en ella." },
    { numero: "20", titulo: "Domicilio plural", contenido: "A falta de residencia habitual, el domicilio se establece en el lugar donde la persona ejerce habitualmente su profesión u oficio." },
    
    // LIBRO PRIMERO - DE LAS PERSONAS
    // TITULO I - DEL PRINCIPIO Y FIN DE LA EXISTENCIA DE LAS PERSONAS
    { numero: "73", titulo: "Principio de existencia", contenido: "La existencia legal de toda persona principia al nacer, esto es, al separarse completamente de su madre. La criatura que muere en el vientre materno, o que perece antes de estar completamente separada de su madre, o que no haya sobrevivido a la separación un momento siquiera, se reputará no haber existido jamás." },
    { numero: "74", titulo: "Nacimiento determina personalidad", contenido: "Para los efectos civiles, el nacimiento determina la personalidad; pero el concebido se tiene por nacido para todos los efectos que le sean favorables, siempre que nazca con las condiciones que expresa el artículo precedente." },
    { numero: "75", titulo: "Momento del nacimiento", contenido: "Se presume que el concebido tiene treinta semanas de vida intrauterina. La ley protege la vida del que está por nacer. El juez, en consecuencia, tomará, a petición de cualquier persona, o de oficio, las providencias que le parezcan convenientes para proteger la existencia del no nacido, siempre que crea que de algún modo peligra." },
    { numero: "76", titulo: "Presunción de concepción", contenido: "De la época del nacimiento se colige la de la concepción, según la regla siguiente: Se presume de derecho que la concepción ha precedido al nacimiento no menos de ciento ochenta días cabales, y no más de trescientos, contados hacia atrás, desde la media noche en que principie el día del nacimiento." },
    { numero: "77", titulo: "Derechos del que está por nacer", contenido: "Los derechos que se deferirían a la criatura que está en el vientre materno, si hubiese nacido y viviese, estarán suspensos hasta que el nacimiento se efectúe. Y si el nacimiento constituye un principio de existencia, entrará el recién nacido en el goce de dichos derechos, como si hubiese existido al tiempo en que se defirieron." },
    { numero: "78", titulo: "Fin de la existencia", contenido: "La persona termina en la muerte natural." },
    { numero: "79", titulo: "Presunción de muerte por desaparecimiento", contenido: "Si pasaren dos años sin haberse tenido noticias del ausente, se presumirá haber muerto éste, si además se probare que se han hecho las posibles diligencias para averiguar su existencia." },
    { numero: "80", titulo: "Declaración de muerte presunta", contenido: "Se podrá pedir la declaración de muerte presunta con respecto de todo individuo que haya desaparecido, ignorándose si vive, y verificándose las condiciones que van a expresarse." },
    { numero: "81", titulo: "Procedimiento muerte presunta", contenido: "Para obtener la declaración de muerte presunta se requiere: 1. Que hayan transcurrido dos años desde las últimas noticias de la desaparición. 2. Que se publiquen tres avisos con intervalo de cuatro meses cada uno." },
    { numero: "82", titulo: "Posesión provisional", contenido: "Declarada judicialmente la muerte presunta, se dará la posesión provisional de los bienes del desaparecido a los herederos presuntivos." },
    { numero: "83", titulo: "Duración posesión provisional", contenido: "El decreto de posesión provisional durará el tiempo necesario para que se cumpla el término de diez años, contados desde que el desaparecido dejó de dar señales de vida." },
    { numero: "84", titulo: "Posesión definitiva", contenido: "Transcurridos los diez años se concederá la posesión definitiva de los bienes del desaparecido." },
    { numero: "85", titulo: "Efectos reaparición", contenido: "Si el desaparecido aparece, recobrará sus bienes en el estado en que se hallen." },
    { numero: "86", titulo: "Personas morales", contenido: "Se llama persona jurídica una persona ficticia, capaz de ejercer derechos y contraer obligaciones civiles, y de ser representada judicial y extrajudicialmente." },
    
    // TITULO II - DEL DOMICILIO Y RESIDENCIA
    { numero: "87", titulo: "Residencia", contenido: "El lugar donde un individuo está de asiento, o donde ejerce habitualmente su profesión u oficio, determina su domicilio civil o vecindad." },
    { numero: "88", titulo: "Domicilio civil", contenido: "El domicilio civil es relativo a una parte determinada del territorio del Estado." },
    { numero: "89", titulo: "Domicilio conyugal", contenido: "El domicilio de los cónyuges es el lugar donde viven de consuno. El de la mujer casada es el mismo que el de su marido." },
    { numero: "90", titulo: "Domicilio del hijo", contenido: "El domicilio del hijo de familia es el de su padre o madre, según el caso." },
    { numero: "91", titulo: "Domicilio de incapaces", contenido: "Los que están bajo guarda tienen el domicilio de su guardador." },
    { numero: "92", titulo: "Domicilio de empleados", contenido: "El domicilio de los criados y dependientes es el de la persona a quien sirven, siempre que residan en la misma casa." },
    { numero: "93", titulo: "Domicilio de personas jurídicas", contenido: "El domicilio de las corporaciones y fundaciones se determina por sus estatutos." },
    { numero: "94", titulo: "Cambio de domicilio", contenido: "El domicilio se conserva aunque el individuo cambie de residencia, si no concurren los requisitos para constituir un nuevo domicilio." },
    { numero: "95", titulo: "Domicilio convencional", contenido: "Se podrá establecer de común acuerdo un domicilio civil especial para los actos judiciales o extrajudiciales a que dé lugar un contrato." },

    // TITULO III - DEL MATRIMONIO
    { numero: "113", titulo: "Definición de matrimonio", contenido: "El matrimonio es un contrato solemne por el cual un hombre y una mujer se unen con el fin de vivir juntos, de procrear y de auxiliarse mutuamente." },
    { numero: "114", titulo: "Requisitos esenciales", contenido: "El matrimonio se constituye y perfecciona por el libre y mutuo consentimiento de los contrayentes, expresado ante el funcionario competente, en la forma y con los requisitos establecidos en este Código." },
    { numero: "115", titulo: "Matrimonio religioso", contenido: "El matrimonio celebrado de conformidad con los ritos de la Iglesia Católica o de otras iglesias o confesiones religiosas que hayan suscrito concordato o tratado de derecho internacional o convenio de derecho público interno con el Estado colombiano, surte todos los efectos civiles." },
    { numero: "116", titulo: "Capacidad para contraer", contenido: "Son hábiles para contraer matrimonio todas las personas que no estén comprendidas en alguna de las siguientes causales de incapacidad." },
    { numero: "117", titulo: "Impedimentos", contenido: "No pueden contraer matrimonio: 1. Los menores de catorce años. 2. Los que carecen de razón. 3. Los que padecen de enfermedad que determine incapacidad para dar consentimiento. 4. Los que sufren de anomalía psíquica que impida el conocimiento del acto." },
    { numero: "118", titulo: "Nulidad del matrimonio", contenido: "El matrimonio es nulo y sin efecto en los casos siguientes: 1. Cuando ha habido error acerca de las personas de ambos contrayentes o de la de uno de ellos. 2. Cuando se ha contraído entre personas que se hallaban en alguno de los impedimentos señalados." },
    { numero: "119", titulo: "Efectos del matrimonio", contenido: "Por el hecho del matrimonio, los cónyuges contraen las obligaciones de guardarse fe, socorrerse y ayudarse mutuamente, en todas las circunstancias de la vida." },
    { numero: "120", titulo: "Deberes de los cónyuges", contenido: "Los cónyuges se deben respeto y consideración mutuos. Ambos cónyuges tienen el deber de vivir juntos." },
    { numero: "140", titulo: "Causales de nulidad", contenido: "El matrimonio es nulo y sin efecto en los siguientes casos: 1. Cuando ha habido error acerca de las personas de ambos contrayentes o de uno de ellos. 2. Cuando se ha contraído entre personas que se hallaban en los impedimentos expresados en los artículos anteriores. 3. Cuando no ha habido libertad en el consentimiento de alguno de los contrayentes." },
    { numero: "141", titulo: "Error en la persona", contenido: "El error acerca de las cualidades personales del otro contrayente no invalida el matrimonio, a menos que dicho error recaiga sobre las cualidades que, tenidas en cuenta la condición del otro contrayente, han de estimarse como determinantes del consentimiento." },
    { numero: "142", titulo: "Fuerza", contenido: "Falta el consentimiento libre cuando ha habido fuerza o miedo grave que vicie el consentimiento." },
    { numero: "143", titulo: "Prescripción de nulidad", contenido: "La acción de nulidad del matrimonio prescribe en un año, contado desde que el error fue conocido o la fuerza cesó." },
    { numero: "144", titulo: "Legitimación para pedir nulidad", contenido: "La nulidad del matrimonio solo puede ser solicitada por los cónyuges y por quienes tengan interés en ella." },
    { numero: "145", titulo: "Matrimonio putativo", contenido: "El matrimonio nulo, si ha sido contraído de buena fe y con las solemnidades legales, produce efectos civiles mientras no se declare su nulidad." },
    { numero: "146", titulo: "Efectos de la nulidad", contenido: "Declarada la nulidad del matrimonio, cesan todos sus efectos civiles, pero quedarán a salvo los derechos adquiridos por terceros de buena fe." },
    { numero: "147", titulo: "Hijos del matrimonio nulo", contenido: "La nulidad del matrimonio no afecta a los hijos habidos o concebidos durante él." },
    { numero: "148", titulo: "Legitimidad de los hijos", contenido: "Los hijos nacidos del matrimonio nulo son legítimos si los padres actuaron de buena fe." },
    { numero: "149", titulo: "Obligaciones subsistentes", contenido: "A pesar de la nulidad, los cónyuges quedan obligados a mantener a los hijos comunes." },
    { numero: "150", titulo: "Disolución del matrimonio", contenido: "El matrimonio civil se disuelve por la muerte real o presunta de uno de los cónyuges o por divorcio judicialmente decretado." },
    { numero: "151", titulo: "Divorcio", contenido: "El divorcio disuelve el vínculo matrimonial y deja a los cónyuges en libertad de contraer nuevo matrimonio." },
    { numero: "152", titulo: "Causales de divorcio", contenido: "Son causales de divorcio: 1. Las relaciones sexuales extramatrimoniales de uno de los cónyuges. 2. El grave e injustificado incumplimiento por parte de alguno de los cónyuges de los deberes que la ley les impone como tales y como padres. 3. Los ultrajes, el trato cruel y los maltratamientos de obra. 4. La embriaguez habitual de uno de los cónyuges. 5. El uso habitual de sustancias alucinógenas o estupefacientes, salvo prescripción médica. 6. Toda enfermedad o anormalidad grave e incurable, física o síquica, de uno de los cónyuges, que ponga en peligro la salud mental o física del otro cónyuge e imposibilite la comunidad matrimonial. 7. Toda conducta de uno de los cónyuges tendiente a corromper o pervertir al otro, a un descendiente, o a personas que estén a su cuidado y convivan bajo el mismo techo. 8. La separación de cuerpos, judicial o de hecho, que haya perdurado por más de dos años. 9. El consentimiento de ambos cónyuges manifestado ante juez competente y reconocido por éste mediante sentencia." },
    { numero: "153", titulo: "Efectos del divorcio", contenido: "El divorcio disuelve la sociedad conyugal y pone fin a los deberes recíprocos de los cónyuges." },
    { numero: "154", titulo: "Custodia de hijos", contenido: "Ejecutoriada la sentencia de divorcio, el juez decidirá sobre la custodia de los hijos menores, teniendo en cuenta el interés superior del menor." },
    { numero: "155", titulo: "Alimentos", contenido: "El cónyuge culpable del divorcio puede ser condenado a pagar alimentos al cónyuge inocente, siempre que éste los necesite." },
    
    // TITULO IV - DE LOS HIJOS
    { numero: "213", titulo: "Hijos legítimos", contenido: "El hijo concebido durante el matrimonio de sus padres es hijo legítimo." },
    { numero: "214", titulo: "Presunción de paternidad", contenido: "El hijo que nace después de expirados los ciento ochenta días subsiguientes al matrimonio, se reputa concebido en él, y tiene por padre al marido." },
    { numero: "215", titulo: "Impugnación de paternidad", contenido: "El marido puede impugnar la paternidad del hijo concebido por su mujer durante el matrimonio, probando que durante todo el tiempo en que, según el artículo 76, pudiera presumirse la concepción, estuvo en absoluta imposibilidad física de tener acceso a la mujer." },
    { numero: "216", titulo: "Plazo para impugnar", contenido: "El marido no puede impugnar la paternidad del hijo después de transcurridos ciento cuarenta días desde aquel en que tuvo conocimiento del parto." },
    { numero: "217", titulo: "Acción de reclamación", contenido: "El hijo tiene acción para reclamar su estado de hijo legítimo contra el padre o la madre, o contra los herederos de ellos." },
    { numero: "218", titulo: "Prueba del estado civil", contenido: "El estado civil de hijo legítimo se prueba por la partida de nacimiento." },
    { numero: "219", titulo: "Prueba supletoria", contenido: "A falta de partida de nacimiento, se probará el estado civil por otros documentos auténticos." },
    { numero: "220", titulo: "Posesión notoria", contenido: "En defecto de los medios de prueba indicados, la posesión notoria de estado de hijo servirá para acreditar tal estado." },
    { numero: "235", titulo: "Reconocimiento de hijo", contenido: "El reconocimiento de un hijo habido fuera del matrimonio podrá hacerse en el acta de nacimiento, por escritura pública, por testamento o por manifestación expresa y directa ante un juez." },
    { numero: "236", titulo: "Efectos del reconocimiento", contenido: "El reconocimiento confiere al hijo el apellido del padre y le da derecho a alimentos." },
    { numero: "237", titulo: "Impugnación del reconocimiento", contenido: "El hijo reconocido puede impugnar el reconocimiento, dentro de los dos años siguientes a su mayoría de edad, probando que el reconociente no es su padre." },
    { numero: "238", titulo: "Acción de investigación", contenido: "El hijo tiene acción para investigar la paternidad de quien pretende ser su padre." },
    { numero: "239", titulo: "Casos de investigación", contenido: "Se permite la investigación de la paternidad en los siguientes casos: 1. En caso de rapto o violación. 2. Cuando existe escrito indubitable del padre. 3. Cuando exista posesión notoria del estado de hijo." },
    { numero: "240", titulo: "Presunciones de paternidad", contenido: "Se presume la paternidad y hay lugar a declararla judicialmente: 1. Cuando hay carta u otro escrito del demandado que contenga una confesión inequívoca de la paternidad. 2. Cuando existan otros medios probatorios que establezcan la paternidad." },
    { numero: "250", titulo: "Patria potestad", contenido: "La patria potestad es el conjunto de derechos que la ley reconoce a los padres sobre sus hijos no emancipados, para facilitar el cumplimiento de los deberes que su calidad les impone." },
    { numero: "251", titulo: "Ejercicio de la patria potestad", contenido: "La patria potestad se ejerce conjuntamente por ambos padres." },
    { numero: "252", titulo: "Representación del hijo", contenido: "Los padres representan al hijo en todos los actos judiciales y extrajudiciales que le conciernan." },
    { numero: "253", titulo: "Administración de bienes", contenido: "Los padres administran los bienes del hijo." },
    { numero: "254", titulo: "Usufructo legal", contenido: "Los padres tienen el usufructo de los bienes del hijo de familia." },
    { numero: "255", titulo: "Exención de usufructo", contenido: "Están exentos del usufructo paterno: 1. Los bienes adquiridos por el hijo en el ejercicio de una industria, profesión u oficio. 2. Los bienes adquiridos por el hijo a título gratuito, cuando el donante o testador así lo haya dispuesto expresamente." },
    { numero: "256", titulo: "Suspensión de patria potestad", contenido: "La patria potestad se suspende por demencia del padre o de la madre, por estar en entredicho de administrar sus propios bienes, y por larga ausencia." },
    { numero: "257", titulo: "Privación de patria potestad", contenido: "El padre o la madre quedan privados de la patria potestad: 1. Por maltrato habitual del hijo. 2. Por haber sido condenados a pena privativa de libertad mayor de un año." },
    { numero: "258", titulo: "Emancipación", contenido: "La emancipación pone fin a la patria potestad. Puede ser voluntaria, legal o judicial." },
    { numero: "259", titulo: "Emancipación legal", contenido: "La emancipación legal se efectúa: 1. Por la muerte del padre o de la madre. 2. Por el matrimonio del hijo. 3. Por haber cumplido el hijo la mayoría de edad." },
    { numero: "260", titulo: "Emancipación judicial", contenido: "La emancipación judicial se efectúa por decreto del juez, cuando los padres maltratan habitualmente al hijo, o le dan órdenes inmorales, o lo abandonan." },
    
    // TITULO V - DE LOS ALIMENTOS
    { numero: "411", titulo: "Obligación alimentaria", contenido: "Se deben alimentos: 1. Al cónyuge. 2. A los descendientes. 3. A los ascendientes. 4. A cargo del cónyuge culpable, al cónyuge divorciado o separado de cuerpos sin su culpa. 5. A los hijos naturales, su posteridad y a los nietos naturales. 6. A los padres naturales. 7. A los hermanos legítimos. 8. Al que hizo una donación cuantiosa si no hubiere sido rescindida o revocada." },
    { numero: "412", titulo: "Contenido de alimentos", contenido: "Los alimentos comprenden todo lo indispensable para el sustento, habitación, vestido, asistencia médica y educación e instrucción del alimentario, si es menor." },
    { numero: "413", titulo: "Alimentos congruos y necesarios", contenido: "Los alimentos se dividen en congruos y necesarios. Congruos son los que habilitan al alimentado para subsistir modestamente de un modo correspondiente a su posición social. Necesarios los que le dan lo que basta para sustentar la vida." },
    { numero: "414", titulo: "Titulares del derecho", contenido: "Se deben alimentos congruos a las personas designadas en los numerales 1, 2, 3, 4 y 5 del artículo 411." },
    { numero: "415", titulo: "Alimentos necesarios", contenido: "Se deben alimentos necesarios a las personas designadas en los numerales 6, 7 y 8 del artículo 411." },
    { numero: "416", titulo: "Orden de prelación", contenido: "El que debe alimentos debe dárselos en el orden siguiente: 1. Al cónyuge. 2. A los descendientes legítimos. 3. A los ascendientes legítimos. 4. A los hijos naturales." },
    { numero: "417", titulo: "Pluralidad de alimentantes", contenido: "Si fueren varios los alimentantes obligados a la prestación de alimentos, entre todos deben satisfacerlos en proporción a su capacidad económica." },
    { numero: "418", titulo: "Cesación de la obligación", contenido: "La obligación de prestar alimentos cesa: 1. Por la muerte del alimentario. 2. Si los descendientes del alimentante se hallan en situación de necesidad." },
    { numero: "419", titulo: "Reducción de alimentos", contenido: "Los alimentos se reducen si las circunstancias del alimentante o alimentario varían." },
    { numero: "420", titulo: "Fijación de alimentos", contenido: "Los alimentos se deben desde la primera demanda, y se pagarán por mesadas anticipadas." },
    { numero: "421", titulo: "Alimentos voluntarios", contenido: "El que hace una donación de alimentos puede imponerle las condiciones que quiera." },
    { numero: "422", titulo: "Renuncia de alimentos", contenido: "El derecho de pedir alimentos no puede transmitirse por causa de muerte, ni venderse o cederse de modo alguno, ni renunciarse." },
    { numero: "423", titulo: "Prueba de necesidad", contenido: "Para pedir alimentos es necesario probar que se carece de bienes y que no se está en condiciones de procurárselos." },
    
    // TITULO VI - DE LAS TUTELAS Y CURADURÍAS
    { numero: "428", titulo: "Guarda", contenido: "Las tutelas y las curadurías o curatelas son cargos impuestos a ciertas personas a favor de aquellos que no pueden dirigirse a sí mismos, o administrar competentemente sus negocios, y que no se hallan bajo potestad de padre o madre, que pueda darles la protección debida." },
    { numero: "429", titulo: "Tutela", contenido: "La tutela y las curadurías generales se extienden no sólo a los bienes sino a la persona de los individuos sometidos a ellas." },
    { numero: "430", titulo: "Tutor", contenido: "El que ejerce la tutela es llamado tutor." },
    { numero: "431", titulo: "Curador", contenido: "El que ejerce la curaduría es llamado curador." },
    { numero: "432", titulo: "Pupilo", contenido: "El individuo sujeto a tutela o curaduría se llama pupilo." },
    { numero: "433", titulo: "Nombramiento", contenido: "La tutela puede ser testamentaria, legítima o dativa." },
    { numero: "434", titulo: "Tutela testamentaria", contenido: "El padre o la madre puede nombrar tutor, por testamento, al hijo que esté bajo su patria potestad." },
    { numero: "435", titulo: "Tutela legítima", contenido: "A falta de tutor testamentario, la tutela corresponde a los parientes." },
    { numero: "436", titulo: "Tutela dativa", contenido: "A falta de tutor testamentario y legítimo, el juez puede nombrar un tutor." },
    { numero: "437", titulo: "Capacidad para ser tutor", contenido: "Puede ser tutor toda persona mayor de edad y de sano juicio." },
    { numero: "438", titulo: "Incapacidad para ser tutor", contenido: "Son incapaces de toda tutela o curaduría: 1. Los ciegos. 2. Los mudos. 3. Los dementes. 4. Los fallidos. 5. Los que carecen de domicilio en la República. 6. Los que no saben leer ni escribir. 7. Los de mala conducta notoria. 8. Los condenados a pena que lleve consigo la inhabilitación para el cargo." },
    { numero: "439", titulo: "Inventario", contenido: "Todo tutor o curador está obligado a inventariar los bienes del pupilo." },
    { numero: "440", titulo: "Rendición de cuentas", contenido: "Todo tutor o curador está obligado a rendir cuenta de su administración." },
    { numero: "441", titulo: "Remuneración", contenido: "El tutor o curador tiene derecho a una remuneración." },
    { numero: "442", titulo: "Remoción", contenido: "El tutor o curador puede ser removido por mala administración." },
    
    // LIBRO SEGUNDO - DE LOS BIENES, SU DOMINIO, POSESIÓN, USO Y GOCE
    { numero: "653", titulo: "Definición de bienes", contenido: "Los bienes consisten en cosas corporales o incorporales. Corporales son las que tienen un ser real y pueden ser percibidas por los sentidos, como una casa, un libro. Incorporales las que consisten en meros derechos, como los créditos y las servidumbres activas." },
    { numero: "654", titulo: "Bienes muebles e inmuebles", contenido: "Las cosas corporales se dividen en muebles e inmuebles." },
    { numero: "655", titulo: "Inmuebles", contenido: "Inmuebles o fincas o bienes raíces son las cosas que no pueden transportarse de un lugar a otro; como las tierras y minas, y las que adhieren permanentemente a ellas, como los edificios, los árboles." },
    { numero: "656", titulo: "Inmuebles por adhesión", contenido: "Las plantas son inmuebles, mientras adhieren al suelo por sus raíces, a menos que estén en macetas o cajones que puedan transportarse de un lugar a otro." },
    { numero: "657", titulo: "Inmuebles por destinación", contenido: "Se reputan inmuebles, aunque por su naturaleza no lo sean, las cosas que están permanentemente destinadas al uso, cultivo y beneficio de un inmueble, sin embargo de que puedan separarse sin detrimento." },
    { numero: "658", titulo: "Bienes muebles", contenido: "Muebles son las que pueden transportarse de un lugar a otro, sea moviéndose ellas a sí mismas como los animales (que por eso se llaman semovientes), sea que sólo se muevan por una fuerza externa, como las cosas inanimadas." },
    { numero: "659", titulo: "Dinero", contenido: "El dinero es cosa mueble." },
    { numero: "660", titulo: "Derechos reales", contenido: "Derecho real es el que tenemos sobre una cosa sin respecto a determinada persona. Son derechos reales el de dominio, el de herencia, los de usufructo, uso o habitación, los de servidumbres activas, el de prenda y el de hipoteca." },
    { numero: "661", titulo: "Derechos personales", contenido: "Derechos personales o créditos son los que sólo pueden reclamarse de ciertas personas que, por un hecho suyo o la sola disposición de la ley, han contraído las obligaciones correlativas." },
    { numero: "662", titulo: "Bienes públicos", contenido: "Las cosas que la naturaleza ha hecho comunes a todos los hombres, como la alta mar, no son susceptibles de dominio, y ninguna nación, corporación o individuo tiene derecho de apropiárselas." },
    { numero: "663", titulo: "Bienes de uso público", contenido: "Los bienes de uso público pertenecen a la Nación." },
    { numero: "664", titulo: "Bienes fiscales", contenido: "Son bienes fiscales todos los que pertenecen a la Unión o a los departamentos, distritos o municipios, y que no son de uso público." },
    { numero: "665", titulo: "Bienes vacantes", contenido: "Son bienes de la Unión todas las tierras que estando situadas dentro de los límites territoriales carecen de otro dueño." },
    { numero: "666", titulo: "Bienes mostrencos", contenido: "Los bienes muebles que no pertenecen a nadie son llamados bienes mostrencos." },
    
    // TITULO II - DEL DOMINIO
    { numero: "669", titulo: "Definición de dominio", contenido: "El dominio (que se llama también propiedad) es el derecho real en una cosa corporal, para gozar y disponer de ella, no siendo contra ley o contra derecho ajeno." },
    { numero: "670", titulo: "Modos de adquirir", contenido: "Los modos de adquirir el dominio son la ocupación, la accesión, la tradición, la sucesión por causa de muerte y la prescripción." },
    { numero: "671", titulo: "Ocupación", contenido: "Por la ocupación se adquiere el dominio de las cosas que no pertenecen a nadie, y cuya adquisición no es prohibida por las leyes o por el derecho internacional." },
    { numero: "672", titulo: "Caza y pesca", contenido: "La caza y la pesca son especies de ocupación por las cuales se adquiere el dominio de los animales bravíos." },
    { numero: "673", titulo: "Invención o hallazgo", contenido: "La invención o hallazgo es una especie de ocupación por la cual el que encuentra una cosa inanimada que no pertenece a nadie, adquiere su dominio, apoderándose de ella." },
    { numero: "713", titulo: "Accesión", contenido: "La accesión es un modo de adquirir por el cual el dueño de una cosa pasa a serlo de lo que ella produce o de lo que se junta a ella." },
    { numero: "714", titulo: "Frutos", contenido: "Se llaman frutos naturales los que da la naturaleza, ayudada o no de la industria humana." },
    { numero: "715", titulo: "Frutos civiles", contenido: "Se llaman frutos civiles los precios, pensiones o cánones de arrendamiento, y los intereses de capitales." },
    { numero: "716", titulo: "Accesión de inmueble a inmueble", contenido: "La accesión de una cosa inmueble a otra puede verificarse de diversas maneras, como el aluvión, la avulsión, la mutación de cauce y la formación de nueva isla." },
    { numero: "717", titulo: "Aluvión", contenido: "Se llama aluvión el aumento que recibe la ribera de un río o lago por el lento e imperceptible retiro de las aguas." },
    { numero: "718", titulo: "Avulsión", contenido: "Sobre la parte del suelo que, por una avenida o por otra fuerza natural violenta, es transportada de un sitio a otro, conserva el dueño su dominio, para el solo efecto de llevársela." },
    { numero: "719", titulo: "Mutación de cauce", contenido: "Si un río varía de curso, el terreno que deja descubierto accede a las heredades contiguas, dentro de sus respectivas líneas de demarcación prolongadas directamente hasta el agua." },
    { numero: "720", titulo: "Formación de isla", contenido: "Las islas que por sucesiva acumulación de arrastres superiores se vayan formando en los ríos, pertenecerán a los dueños de las riberas fronteras dentro de sus respectivas líneas de demarcación." },
    { numero: "721", titulo: "Accesión de mueble a mueble", contenido: "La accesión de una cosa mueble a otra puede verificarse por adjunción, especificación o mezcla." },
    { numero: "722", titulo: "Adjunción", contenido: "La adjunción es una especie de accesión, y se verifica cuando dos cosas muebles pertenecientes a diferentes dueños se juntan una a otra, pero de modo que puedan separarse y subsistir cada una después de separada." },
    { numero: "723", titulo: "Especificación", contenido: "Otra especie de accesión es la especificación, que se verifica cuando de la materia perteneciente a una persona, hace otra persona una obra o artefacto cualquiera." },
    { numero: "724", titulo: "Mezcla", contenido: "Si se forma una cosa por mezcla de materias áridas o líquidas, pertenecientes a diferentes dueños, no habiendo conocimiento del hecho por una parte, ni mala fe por otra, el dominio de la cosa pertenecerá a dichos dueños proindiviso, a prorrata del valor de la materia que a cada uno pertenezca." },
    { numero: "725", titulo: "Accesión de mueble a inmueble", contenido: "La accesión de una cosa mueble a un inmueble sigue las reglas de la edificación en suelo ajeno." },
    { numero: "726", titulo: "Edificación en suelo propio", contenido: "Si se edifica con materiales ajenos en suelo propio, el dueño del suelo se hará dueño de los materiales por el hecho de incorporarlos en la construcción, pero estará obligado a pagar su valor." },
    { numero: "727", titulo: "Edificación en suelo ajeno", contenido: "Si se edifica o planta en suelo ajeno, el dueño del terreno puede hacer suyo lo edificado o plantado, pagando las indemnizaciones prescritas a favor de los poseedores de buena o mala fe." },
    { numero: "728", titulo: "Buena fe del que edifica", contenido: "Si el que edifica, planta o siembra es de buena fe, tendrá derecho a que se le pague el precio de los materiales y de la mano de obra, o a que se le deje lo edificado, sembrado o plantado, previa indemnización al dueño del terreno." },
    { numero: "729", titulo: "Mala fe del que edifica", contenido: "El que de mala fe edifica, planta o siembra en terreno ajeno, pierde lo edificado, plantado o sembrado, sin derecho a indemnización alguna." },
    { numero: "739", titulo: "Tradición", contenido: "La tradición es un modo de adquirir el dominio de las cosas, y consiste en la entrega que el dueño hace de ellas a otro, habiendo por una parte la facultad e intención de transferir el dominio, y por otra la capacidad e intención de adquirirlo." },
    { numero: "740", titulo: "Requisitos de la tradición", contenido: "Para que la tradición sea válida debe ser hecha voluntariamente por el tradente o por su representante." },
    { numero: "741", titulo: "Título de la tradición", contenido: "Se requiere también para la validez de la tradición que haya un título traslaticio de dominio, como el de venta, permuta, donación, etc." },
    { numero: "742", titulo: "Tradición de inmuebles", contenido: "La tradición del dominio de los bienes raíces se efectúa por la inscripción del título en la oficina de registro de instrumentos públicos." },
    { numero: "743", titulo: "Tradición de muebles", contenido: "La tradición de una cosa corporal mueble debe hacerse significando una de las partes a la otra que le transfiere el dominio, y figurando esta transferencia por uno de los medios siguientes: 1. Permitiéndole la aprehensión material de una cosa presente. 2. Mostrándosela. 3. Entregándole las llaves del granero, almacén, cofre o lugar cualquiera en que esté guardada la cosa. 4. Encargándose el uno de poner la cosa a disposición del otro en el lugar convenido." },
    { numero: "744", titulo: "Tradición por constituto posesorio", contenido: "Cuando el tradente conserva la tenencia de la cosa como arrendatario o depositario, se entiende hecha la tradición si en el respectivo contrato de arrendamiento o depósito se estipuló cláusula de constituto posesorio." },
    
    // POSESIÓN
    { numero: "762", titulo: "Definición de posesión", contenido: "La posesión es la tenencia de una cosa determinada con ánimo de señor o dueño, sea que el dueño o el que se da por tal, tenga la cosa por sí mismo, o por otra persona que la tenga en lugar y a nombre de él." },
    { numero: "763", titulo: "Poseedor a nombre ajeno", contenido: "El poseedor es reputado dueño, mientras otra persona no justifica serlo." },
    { numero: "764", titulo: "Posesión regular e irregular", contenido: "Se llama posesión regular la que procede de justo título y ha sido adquirida de buena fe, aunque la buena fe no subsista después de adquirida la posesión. Se llama posesión irregular la que carece de uno o más de los requisitos señalados." },
    { numero: "765", titulo: "Justo título", contenido: "Justo título es el que legalmente basta para atribuir el dominio. Puede ser constitutivo, como la ocupación, la accesión, la prescripción; traslaticio de dominio, como la venta, la permuta, la donación entre vivos; declarativo de dominio, como la sentencia del juicio de partición." },
    { numero: "766", titulo: "Buena fe", contenido: "La buena fe es la conciencia de haberse adquirido el dominio de la cosa por medios legítimos exentos de fraudes y de todo otro vicio." },
    { numero: "767", titulo: "Presunción de buena fe", contenido: "La buena fe se presume, excepto en los casos en que la ley establece la presunción contraria." },
    { numero: "768", titulo: "Error en materia de derecho", contenido: "El error en materia de derecho constituye una presunción de mala fe, que no admite prueba en contrario." },
    { numero: "769", titulo: "Posesión de mala fe", contenido: "La mala fe es el conocimiento de que la cosa no pertenece al que la tiene como propia." },
    { numero: "770", titulo: "Posesión no se transmite", contenido: "La posesión es un hecho, y no se transmite de una persona a otra." },
    { numero: "771", titulo: "Adquisición de posesión", contenido: "La posesión se adquiere por la aprehensión material o jurídica de la cosa, con ánimo de hacerla propia." },
    { numero: "772", titulo: "Capacidad para poseer", contenido: "Para que la posesión se adquiera, se requiere capacidad de adquirir por cualquier título." },
    { numero: "773", titulo: "Pérdida de posesión", contenido: "Se deja de poseer una cosa desde que otro se apodera de ella, con ánimo de hacerla suya." },
    { numero: "774", titulo: "Abandono", contenido: "Se deja también de poseer por el abandono de la cosa." },
    { numero: "775", titulo: "Restitución", contenido: "El poseedor de mala fe es obligado a restituir los frutos naturales y civiles de la cosa, y no solamente los percibidos, sino los que el dueño hubiera podido percibir con mediana inteligencia y actividad." },
    { numero: "776", titulo: "Mejoras", contenido: "En cuanto a las mejoras, se consideran necesarias las que son indispensables para la conservación de la cosa; útiles las que aumentan el valor venal de la cosa; y voluptuarias las de mero lujo, recreo u ornato." },
    { numero: "777", titulo: "Derecho de retención", contenido: "El poseedor de buena fe vencido en el juicio de reivindicación tiene derecho a que se le abonen las mejoras necesarias y útiles." },
    
    // PRESCRIPCIÓN
    { numero: "2512", titulo: "Definición de prescripción", contenido: "La prescripción es un modo de adquirir las cosas ajenas, o de extinguir las acciones o derechos ajenos, por haberse poseído las cosas, o no haberse ejercido dichas acciones y derechos, durante cierto lapso de tiempo, y concurriendo los demás requisitos legales." },
    { numero: "2513", titulo: "Clases de prescripción", contenido: "La prescripción puede ser adquisitiva o extintiva. La prescripción adquisitiva es un modo de adquirir el dominio y demás derechos reales. La prescripción extintiva es un modo de extinguir las acciones y derechos." },
    { numero: "2514", titulo: "Renuncia de prescripción", contenido: "La prescripción puede ser renunciada expresa o tácitamente; pero sólo después de cumplida." },
    { numero: "2515", titulo: "Personas que pueden prescribir", contenido: "Pueden prescribir los que están en posesión de los bienes ajenos." },
    { numero: "2516", titulo: "Cosas que no se prescriben", contenido: "No se pueden adquirir por prescripción las cosas que están fuera del comercio." },
    { numero: "2517", titulo: "Prescripción ordinaria", contenido: "La prescripción adquisitiva ordinaria requiere posesión regular no interrumpida durante tres años para los muebles y diez años para los inmuebles." },
    { numero: "2518", titulo: "Prescripción extraordinaria", contenido: "La prescripción adquisitiva extraordinaria requiere posesión, aunque sea irregular, durante veinte años." },
    { numero: "2519", titulo: "Interrupción de prescripción", contenido: "La prescripción se interrumpe naturalmente cuando sin haber pasado la posesión a otras manos, se ha hecho imposible el ejercicio de actos posesorios." },
    { numero: "2520", titulo: "Interrupción civil", contenido: "La interrupción civil de la prescripción se produce por todo acto que constituye al poseedor en mala fe." },
    { numero: "2521", titulo: "Suspensión de prescripción", contenido: "La prescripción se suspende a favor de los menores de edad, los dementes, los sordomudos que no puedan darse a entender por escrito, y todos los que estén bajo potestad paterna o bajo tutela o curaduría." },
    { numero: "2522", titulo: "Prescripción de acciones", contenido: "La prescripción extintiva se cuenta desde que la obligación se hizo exigible." },
    { numero: "2523", titulo: "Plazo de prescripción de acciones", contenido: "La acción ejecutiva prescribe en diez años, y la ordinaria en veinte." },
    { numero: "2524", titulo: "Prescripción de corto tiempo", contenido: "Prescriben en tres años: 1. La acción de los mercaderes, proveedores y artesanos por el precio de los artículos que despachan al menudeo. 2. La de toda clase de personas por el precio de servicios que se prestan periódica o accidentalmente." },
    { numero: "2525", titulo: "Prescripción de un año", contenido: "Prescriben en un año: 1. La acción de los hoteleros, fondistas y posaderos por el precio del hospedaje, y la de los acarreadores por el precio de transporte. 2. La de los profesores y maestros por sus honorarios." },
    { numero: "2526", titulo: "Prescripción de dos años", contenido: "Prescriben en dos años la acción de los médicos, cirujanos, boticarios, y demás personas que ejercen profesiones análogas, por sus honorarios." },
    { numero: "2527", titulo: "Sentencias", contenido: "Las acciones que proceden de una sentencia ejecutoriada prescriben en veinte años." },
    { numero: "2528", titulo: "Hipoteca", contenido: "La acción hipotecaria prescribe junto con la obligación a que accede." },
    { numero: "2529", titulo: "Prescripción de pensiones", contenido: "Las pensiones alimenticias atrasadas prescriben en cinco años." },
    { numero: "2530", titulo: "Imprescriptibilidad", contenido: "No prescriben: 1. La acción que proviene de un delito o cuasidelito que recaiga sobre cosa que tiene señor. 2. La acción para pedir la partición de una cosa común." },
    { numero: "2531", titulo: "Acción reivindicatoria", contenido: "La acción reivindicatoria no prescribe sino cuando se ha completado el tiempo de la prescripción adquisitiva por el que pretende adquirir por este modo." },
    { numero: "2532", titulo: "Interrupción prescripción extintiva", contenido: "La prescripción que extingue las acciones ajenas, puede interrumpirse, ya natural, ya civilmente. Se interrumpe naturalmente por el hecho de reconocer el deudor la obligación, ya expresa, ya tácitamente. Se interrumpe civilmente por la demanda judicial." },
    { numero: "2533", titulo: "Suspensión de prescripción extintiva", contenido: "La prescripción extintiva se suspende a favor de las mismas personas a favor de quienes se suspende la prescripción adquisitiva." },
    { numero: "2534", titulo: "Renuncia de prescripción cumplida", contenido: "Cumplido el plazo de prescripción, el deudor puede renunciarla." },
    { numero: "2535", titulo: "Prescripción en curso", contenido: "La prescripción en curso no puede renunciarse." },
    
    // LIBRO TERCERO - SUCESIONES
    { numero: "1008", titulo: "Sucesión por causa de muerte", contenido: "Se sucede a una persona difunta a título universal o a título singular. El título es universal cuando se sucede al difunto en todos sus bienes, derechos y obligaciones transmisibles o en una cuota de ellos, como la mitad, tercio o quinto." },
    { numero: "1009", titulo: "Heredero y legatario", contenido: "El título es singular cuando se sucede en una o más especies o cuerpos ciertos, como tal caballo, tal casa; o en una o más especies indeterminadas de cierto género, como un caballo, tres vacas, seiscientos pesos, cuarenta fanegas de trigo." },
    { numero: "1010", titulo: "Sucesión testada e intestada", contenido: "La sucesión en los bienes de una persona difunta puede ser parte testamentaria y parte intestada." },
    { numero: "1011", titulo: "Asignaciones", contenido: "Se llaman asignaciones por causa de muerte las que hace la ley o el testamento de una persona difunta, para suceder en sus bienes." },
    { numero: "1012", titulo: "Asignatario", contenido: "Asignatario es la persona a quien se hace la asignación." },
    { numero: "1013", titulo: "Apertura de la sucesión", contenido: "La sucesión en los bienes de una persona se abre al momento de su muerte, en su último domicilio, salvos los casos expresamente exceptuados." },
    { numero: "1014", titulo: "Delación de la herencia", contenido: "La delación de una asignación es el actual llamamiento de la ley a aceptarla o repudiarla." },
    { numero: "1015", titulo: "Capacidad para suceder", contenido: "Para ser capaz de suceder es necesario existir al tiempo de abrirse la sucesión." },
    { numero: "1016", titulo: "Indignidades", contenido: "Son indignos de suceder al difunto como herederos o legatarios: 1. El que ha cometido el crimen de homicidio en la persona del difunto, o ha intervenido en este crimen por obra o consejo, o la dejó perecer pudiendo salvarla. 2. El que cometió atentado grave contra la vida, el honor o los bienes de la persona de cuya sucesión se trata, o de su cónyuge, o de cualquiera de sus ascendientes o descendientes, con tal que dicho atentado se pruebe por sentencia ejecutoriada. 3. El consanguíneo dentro del sexto grado inclusive que, en el estado de demencia o destitución de la persona de cuya sucesión se trata, no la socorrió pudiendo." },
    { numero: "1017", titulo: "Efectos de la indignidad", contenido: "La indignidad no produce efecto alguno si no es declarada en juicio, a instancia de cualquiera de los interesados en la exclusión del heredero o legatario indigno." },
    { numero: "1018", titulo: "Purga de indignidad", contenido: "La indignidad se purga en diez años de posesión de la herencia o legado." },
    { numero: "1019", titulo: "Transmisión de la indignidad", contenido: "La indignidad del padre o madre no perjudica a sus hijos o descendientes." },
    
    // TESTAMENTOS
    { numero: "1055", titulo: "Testamento", contenido: "El testamento es un acto más o menos solemne, en que una persona dispone del todo o de una parte de sus bienes para que tenga pleno efecto después de sus días, conservando la facultad de revocar las disposiciones contenidas en él mientras viva." },
    { numero: "1056", titulo: "Solemnidades", contenido: "Las solemnidades del testamento son aquellas sin cuya observancia no tiene el testamento valor alguno." },
    { numero: "1057", titulo: "Capacidad para testar", contenido: "No son hábiles para testar: 1. El impúber. 2. El que se hallare bajo interdicción por causa de demencia. 3. El que actualmente no estuviere en su sano juicio por ebriedad u otra causa. 4. Todo el que no pudiere expresar su voluntad claramente." },
    { numero: "1058", titulo: "Testamentos solemnes", contenido: "El testamento solemne es abierto o cerrado. Testamento abierto, nuncupativo o público, es aquel en que el testador hace sabedores de sus disposiciones a los testigos; y testamento cerrado o secreto, es aquel en que no es necesario que los testigos tengan conocimiento de ellas." },
    { numero: "1059", titulo: "Testamento ante notario", contenido: "El testamento solemne, abierto o cerrado, debe otorgarse ante notario, o ante cinco testigos si no hubiere notario en el lugar." },
    { numero: "1060", titulo: "Testigos", contenido: "No pueden ser testigos en un testamento solemne: 1. Los menores de dieciocho años. 2. Los que se hallaren en interdicción por causa de demencia. 3. Los actualmente privados de razón. 4. Los ciegos. 5. Los sordos. 6. Los mudos. 7. Los condenados a alguna de las penas designadas en el artículo 1028, y en general, todos aquellos que no puedan hacer valer su testimonio en juicio." },
    { numero: "1061", titulo: "Unidad del acto", contenido: "El testamento solemne es siempre escrito." },
    { numero: "1062", titulo: "Fecha y firma", contenido: "El testamento debe expresar el lugar, día, mes y año en que se otorga." },
    { numero: "1063", titulo: "Lectura del testamento", contenido: "El testamento abierto podrá haberse escrito previamente." },
    { numero: "1064", titulo: "Testamento cerrado", contenido: "Lo que constituye esencialmente el testamento cerrado es el acto en que el testador presenta al notario y testigos una escritura cerrada, declarando de viva voz que en aquella escritura se contiene su testamento." },
    { numero: "1065", titulo: "Apertura testamento cerrado", contenido: "El testamento cerrado, antes de recibir su ejecución, debe ser presentado al juez." },
    
    // SUCESIÓN INTESTADA
    { numero: "1037", titulo: "Sucesión intestada", contenido: "Las leyes reglan la sucesión en los bienes de que el difunto no ha dispuesto, o si dispuso, no lo hizo conforme a derecho, o no han tenido efecto sus disposiciones." },
    { numero: "1038", titulo: "Órdenes hereditarios", contenido: "Son llamados a la sucesión intestada: los descendientes; los hijos adoptivos; los ascendientes; los hijos de éstos; los hermanos; los hijos de éstos; el cónyuge supérstite; el Instituto Colombiano de Bienestar Familiar." },
    { numero: "1039", titulo: "Primer orden", contenido: "Los hijos legítimos, adoptivos y extramatrimoniales, excluyen a todos los otros herederos y recibirán entre ellos iguales cuotas, sin perjuicio de la porción conyugal." },
    { numero: "1040", titulo: "Segundo orden", contenido: "Si el difunto no deja posteridad, le sucederán sus ascendientes de grado más próximo, su cónyuge y sus hermanos conjuntamente." },
    { numero: "1041", titulo: "Tercer orden", contenido: "Si el difunto no deja descendientes, ni ascendientes, ni cónyuge, ni hermanos, le sucederán sus sobrinos." },
    { numero: "1042", titulo: "Cuarto orden", contenido: "A falta de descendientes, ascendientes, cónyuge, hermanos y sobrinos, sucederá el Instituto Colombiano de Bienestar Familiar." },
    { numero: "1043", titulo: "Representación", contenido: "La representación es una ficción legal en que se supone que una persona tiene el lugar y por consiguiente el grado de parentesco y los derechos hereditarios que tendría su padre o madre si éste o ésta no quisiese o no pudiese suceder." },
    { numero: "1044", titulo: "Efectos de la representación", contenido: "Los que suceden por representación heredan en todos casos por estirpes, es decir, que cualquiera que sea el número de los hijos que representan al padre o madre, toman entre todos y por iguales partes la porción que hubiera cabido al padre o madre representado." },
    
    // LEGÍTIMAS Y MEJORAS
    { numero: "1226", titulo: "Legítimas", contenido: "Legítima es aquella cuota de los bienes de un difunto que la ley asigna a ciertas personas llamadas legitimarios." },
    { numero: "1227", titulo: "Legitimarios", contenido: "Son legitimarios: 1. Los hijos legítimos, adoptivos y extramatrimoniales, personalmente o representados. 2. Los ascendientes. 3. Los padres adoptantes. 4. El cónyuge sobreviviente." },
    { numero: "1228", titulo: "Cuantía de las legítimas", contenido: "La mitad de los bienes, previas las deducciones indicadas en el artículo 1016, y las agregaciones que en seguida se expresan, se dividirá por cabezas o estirpes entre los respectivos legitimarios, según el orden y reglas de la sucesión intestada." },
    { numero: "1229", titulo: "Mejora", contenido: "La cuarta de mejoras es aquella cuota de la herencia que el testador puede asignar a uno o más de sus descendientes." },
    { numero: "1230", titulo: "Porción de libre disposición", contenido: "La cuarta parte de los bienes es de libre disposición." },
    { numero: "1231", titulo: "Acción de reforma", contenido: "Los legitimarios a quienes el testador no haya dejado lo que por ley les corresponde, tienen acción de reforma del testamento." },
    { numero: "1232", titulo: "Acción de petición de herencia", contenido: "El que probare su derecho a una herencia, ocupada por otra persona en calidad de heredero, tendrá acción para que se le adjudique la herencia, y se le restituyan las cosas hereditarias." },
    { numero: "1233", titulo: "Prescripción de la acción", contenido: "La acción de petición de herencia expira en diez años." },
    
    // LIBRO CUARTO - OBLIGACIONES Y CONTRATOS
    { numero: "1494", titulo: "Fuentes de las obligaciones", contenido: "Las obligaciones nacen, ya del concurso real de las voluntades de dos o más personas, como en los contratos o convenciones; ya de un hecho voluntario de la persona que se obliga, como en la aceptación de una herencia o legado y en todos los cuasicontratos; ya a consecuencia de un hecho que ha inferido injuria o daño a otra persona, como en los delitos; ya por disposición de la ley, como entre los padres y los hijos de familia." },
    { numero: "1495", titulo: "Contrato", contenido: "Contrato o convención es un acto por el cual una parte se obliga para con otra a dar, hacer o no hacer alguna cosa. Cada parte puede ser de una o de muchas personas." },
    { numero: "1496", titulo: "Contrato unilateral y bilateral", contenido: "El contrato es unilateral cuando una de las partes se obliga para con otra que no contrae obligación alguna; y bilateral, cuando las partes contratantes se obligan recíprocamente." },
    { numero: "1497", titulo: "Contrato gratuito y oneroso", contenido: "El contrato es gratuito o de beneficencia cuando sólo tiene por objeto la utilidad de una de las partes, sufriendo la otra el gravamen; y oneroso, cuando tiene por objeto la utilidad de ambos contratantes, gravándose cada uno a beneficio del otro." },
    { numero: "1498", titulo: "Contrato conmutativo y aleatorio", contenido: "El contrato oneroso es conmutativo cuando cada una de las partes se obliga a dar o hacer una cosa que se mira como equivalente a lo que la otra parte debe dar o hacer a su vez; y si el equivalente consiste en una contingencia incierta de ganancia o pérdida, se llama aleatorio." },
    { numero: "1499", titulo: "Contrato principal y accesorio", contenido: "El contrato es principal cuando subsiste por sí mismo sin necesidad de otra convención, y accesorio cuando tiene por objeto asegurar el cumplimiento de una obligación principal, de manera que no pueda subsistir sin ella." },
    { numero: "1500", titulo: "Contrato real, solemne y consensual", contenido: "El contrato es real cuando, para que sea perfecto, es necesaria la tradición de la cosa a que se refiere; es solemne cuando está sujeto a la observancia de ciertas formalidades especiales, de manera que sin ellas no produce ningún efecto civil; y es consensual cuando se perfecciona por el solo consentimiento." },
    { numero: "1501", titulo: "Elementos del contrato", contenido: "Se distinguen en cada contrato las cosas que son de su esencia, las que son de su naturaleza, y las puramente accidentales. Son de la esencia de un contrato aquellas cosas sin las cuales, o no produce efecto alguno, o degeneran en otro contrato diferente; son de la naturaleza de un contrato las que no siendo esenciales en él, se entienden pertenecerle, sin necesidad de una cláusula especial; y son accidentales a un contrato aquellas que ni esencial ni naturalmente le pertenecen, y que se le agregan por medio de cláusulas especiales." },
    { numero: "1502", titulo: "Requisitos de validez", contenido: "Para que una persona se obligue a otra por un acto o declaración de voluntad, es necesario: 1. Que sea legalmente capaz. 2. Que consienta en dicho acto o declaración y su consentimiento no adolezca de vicio. 3. Que recaiga sobre un objeto lícito. 4. Que tenga una causa lícita." },
    { numero: "1503", titulo: "Capacidad", contenido: "Toda persona es legalmente capaz, excepto aquéllas que la ley declara incapaces." },
    { numero: "1504", titulo: "Incapaces", contenido: "Son absolutamente incapaces los dementes, los impúberes y sordomudos que no pueden darse a entender por escrito. Sus actos no producen ni aun obligaciones naturales, y no admiten caución. Son también incapaces los menores adultos que no han obtenido habilitación de edad y los disipadores que se hallen bajo interdicción. Pero la incapacidad de estas personas no es absoluta, y sus actos pueden tener valor en ciertas circunstancias y bajo ciertos respectos determinados por las leyes." },
    { numero: "1505", titulo: "Incapacidades particulares", contenido: "Además de estas incapacidades hay otras particulares que consisten en la prohibición que la ley ha impuesto a ciertas personas para ejecutar ciertos actos." },
    { numero: "1506", titulo: "Nulidad por incapacidad", contenido: "Los actos y contratos de los relativamente incapaces pueden ser ratificados por ellos mismos cuando sean mayores y capaces." },
    { numero: "1507", titulo: "Representación", contenido: "Lo que una persona ejecuta a nombre de otra, estando facultada por ella o por la ley para representarla, produce respecto del representado iguales efectos que si hubiese contratado él mismo." },
    { numero: "1508", titulo: "Vicios del consentimiento", contenido: "Los vicios de que puede adolecer el consentimiento son: error, fuerza y dolo." },
    { numero: "1509", titulo: "Error de derecho", contenido: "El error sobre un punto de derecho no vicia el consentimiento." },
    { numero: "1510", titulo: "Error de hecho", contenido: "El error de hecho vicia el consentimiento cuando recae sobre la especie de acto o contrato que se ejecuta o celebra." },
    { numero: "1511", titulo: "Error en la sustancia", contenido: "El error de hecho vicia asimismo el consentimiento cuando la sustancia o calidad esencial del objeto sobre que versa el acto o contrato es diversa de lo que se cree." },
    { numero: "1512", titulo: "Error en la persona", contenido: "El error acerca de la persona con quien se tiene intención de contratar, no vicia el consentimiento, salvo que la consideración de esta persona sea la causa principal del contrato." },
    { numero: "1513", titulo: "Fuerza", contenido: "La fuerza no vicia el consentimiento sino cuando es capaz de producir una impresión fuerte en una persona de sano juicio, tomando en cuenta su edad, sexo y condición." },
    { numero: "1514", titulo: "Temor reverencial", contenido: "El temor reverencial, esto es, el solo temor de desagradar a las personas a quienes se debe sumisión y respeto, no basta para viciar el consentimiento." },
    { numero: "1515", titulo: "Dolo", contenido: "El dolo no vicia el consentimiento sino cuando es obra de una de las partes, y cuando además aparece claramente que sin él no hubiera contratado." },
    { numero: "1516", titulo: "Dolo incidental", contenido: "El dolo que no es determinante da lugar solamente a la acción de perjuicios contra la persona o personas que lo han fraguado o que se han aprovechado de él." },
    { numero: "1517", titulo: "Objeto ilícito", contenido: "Hay objeto ilícito en todo lo que contraviene al derecho público de la Nación." },
    { numero: "1518", titulo: "Enajenación de cosas fuera del comercio", contenido: "Hay asimismo objeto ilícito en la enajenación de las cosas que no están en el comercio." },
    { numero: "1519", titulo: "Pactos sobre sucesión futura", contenido: "El derecho de suceder por causa de muerte a una persona viva no puede ser objeto de una donación o contrato." },
    { numero: "1520", titulo: "Condonación del dolo futuro", contenido: "La condonación del dolo futuro no vale." },
    { numero: "1521", titulo: "Enajenaciones prohibidas", contenido: "Hay asimismo objeto ilícito en la enajenación: 1. De las cosas que no están en el comercio. 2. De los derechos o privilegios que no pueden transferirse a otra persona. 3. De las cosas embargadas por decreto judicial, a menos que el juez lo autorice o el acreedor consienta en ello." },
    { numero: "1522", titulo: "Deudas de juegos ilícitos", contenido: "Hay asimismo objeto ilícito en las deudas contraídas en juegos de azar." },
    { numero: "1523", titulo: "Actos prohibidos por ley", contenido: "Hay asimismo objeto ilícito en todo contrato prohibido por las leyes." },
    { numero: "1524", titulo: "Causa", contenido: "No puede haber obligación sin una causa real y lícita; pero no es necesario expresarla. La pura liberalidad o beneficencia es causa suficiente. Se entiende por causa el motivo que induce al acto o contrato." },
    { numero: "1525", titulo: "Causa ilícita", contenido: "No podrá repetirse lo que se haya dado o pagado por un objeto o causa ilícita a sabiendas." },
    { numero: "1526", titulo: "Efecto de los contratos", contenido: "Todo contrato legalmente celebrado es una ley para los contratantes, y no puede ser invalidado sino por su consentimiento mutuo o por causas legales." },
    { numero: "1527", titulo: "Buena fe", contenido: "Los contratos deben ejecutarse de buena fe, y por consiguiente obligan no solo a lo que en ellos se expresa, sino a todas las cosas que emanan precisamente de la naturaleza de la obligación, o que por ley pertenecen a ella." },
    { numero: "1528", titulo: "Interpretación del contrato", contenido: "Conocida claramente la intención de los contratantes, debe estarse a ella más que a lo literal de las palabras." },
    { numero: "1529", titulo: "Cláusulas ambiguas", contenido: "Las cláusulas ambiguas se interpretarán por las que sean claras." },
    { numero: "1530", titulo: "Interpretación restrictiva", contenido: "Por generales que sean los términos de un contrato, solo se aplicarán a la materia sobre que se ha contratado." },
    { numero: "1531", titulo: "Cláusulas de uso común", contenido: "Las cláusulas de uso común se presumen aunque no se expresen." },
    { numero: "1532", titulo: "Interpretación en favor del deudor", contenido: "No pudiendo aplicarse ninguna de las reglas precedentes de interpretación, se interpretarán las cláusulas ambiguas a favor del deudor." },
    { numero: "1533", titulo: "Interpretación contra el redactor", contenido: "Las cláusulas ambiguas que hayan sido extendidas o dictadas por una de las partes, sea acreedora o deudora, se interpretarán contra ella." },
    { numero: "1534", titulo: "Cláusula penal", contenido: "La cláusula penal es aquella en que una persona, para asegurar el cumplimiento de una obligación, se sujeta a una pena que consiste en dar o hacer algo en caso de no ejecutar o retardar la obligación principal." },
    { numero: "1535", titulo: "Efecto de la cláusula penal", contenido: "La pena no puede pedirse juntamente con la obligación principal, a no ser que se haya estipulado así expresamente, o que aparezca haberse estipulado la pena por el simple retardo." },
    { numero: "1536", titulo: "Exigibilidad de la pena", contenido: "Háyase o no estipulado un término dentro del cual deba cumplirse la obligación principal, el deudor no incurre en la pena sino cuando se ha constituido en mora." },
    
    // OBLIGACIONES
    { numero: "1602", titulo: "Efectos de las obligaciones", contenido: "Todo contrato legalmente celebrado es una ley para los contratantes, y no puede ser invalidado sino por su consentimiento mutuo o por causas legales." },
    { numero: "1603", titulo: "Buena fe contractual", contenido: "Los contratos deben ejecutarse de buena fe, y por consiguiente obligan no solo a lo que en ellos se expresa, sino a todas las cosas que emanan precisamente de la naturaleza de la obligación, o que por la ley pertenecen a ella." },
    { numero: "1604", titulo: "Responsabilidad contractual", contenido: "El deudor no es responsable sino de la culpa lata en los contratos que por su naturaleza solo son útiles al acreedor; es responsable de la leve en los contratos que se hacen para beneficio recíproco de las partes; y de la levísima en los contratos en que el deudor es el único que reporta beneficio." },
    { numero: "1605", titulo: "Mora del deudor", contenido: "El deudor está en mora: 1. Cuando no ha cumplido la obligación dentro del término estipulado; salvo que la ley, en casos especiales, exija que se requiera al deudor para constituirlo en mora. 2. Cuando la cosa no ha podido ser dada o ejecutada sino dentro de cierto tiempo y el deudor lo ha dejado pasar sin darla o ejecutarla. 3. En los demás casos, cuando el deudor ha sido judicialmente reconvenido por el acreedor." },
    { numero: "1606", titulo: "Mora del acreedor", contenido: "El acreedor está en mora cuando el deudor le ofrece el pago de la deuda y el acreedor se niega injustificadamente a recibirlo." },
    { numero: "1607", titulo: "Riesgo", contenido: "El riesgo del cuerpo cierto cuya entrega se deba, es siempre a cargo del acreedor." },
    { numero: "1608", titulo: "Pérdida de la cosa debida", contenido: "La pérdida de la cosa debida extingue la obligación." },
    { numero: "1609", titulo: "Excepción de contrato no cumplido", contenido: "En los contratos bilaterales ninguno de los contratantes está en mora dejando de cumplir lo pactado, mientras el otro no lo cumpla por su parte, o no se allana a cumplirlo en la forma y tiempo debidos." },
    { numero: "1610", titulo: "Resolución por incumplimiento", contenido: "Si la cosa es un cuerpo cierto, y la obligación de entregarlo es alternativa con la de hacer algo, tiene el acreedor la elección." },
    { numero: "1611", titulo: "Acción resolutoria", contenido: "En los contratos bilaterales va envuelta la condición resolutoria de no cumplirse por uno de los contratantes lo pactado." },
    { numero: "1612", titulo: "Indemnización de perjuicios", contenido: "La indemnización de perjuicios comprende el daño emergente y lucro cesante, ya provengan de no haberse cumplido la obligación, o de haberse cumplido imperfectamente, o de haberse retardado el cumplimiento." },
    { numero: "1613", titulo: "Daño emergente y lucro cesante", contenido: "La indemnización de perjuicios comprende el daño emergente y lucro cesante." },
    { numero: "1614", titulo: "Prueba de perjuicios", contenido: "El acreedor que demanda perjuicios debe probar la existencia del daño y su cuantía." },
    { numero: "1615", titulo: "Liquidación de perjuicios", contenido: "La liquidación de perjuicios se hace judicialmente, a menos que las partes la hayan pactado." },
    { numero: "1616", titulo: "Perjuicios previsibles", contenido: "Si no se puede imputar dolo al deudor, solo es responsable de los perjuicios que se previeron o pudieron preverse al tiempo del contrato." },
    { numero: "1617", titulo: "Intereses moratorios", contenido: "Si la obligación es de pagar una cantidad de dinero, la indemnización de perjuicios por la mora está sujeta a las reglas siguientes: 1. Se siguen debiendo los intereses convencionales, si se ha pactado un interés superior al legal, o empiezan a deberse los intereses legales, en el caso contrario. 2. El acreedor no tiene necesidad de justificar perjuicios cuando solo cobra intereses; basta el hecho del retardo." },
  ]
};
